# マーケティング課題の機械学習タイプ分類

marketing_tasks = [
    {
        "task": "過去の購入履歴から、来月解約しそうな顧客を特定する",
        "data_available": "解約した顧客・継続した顧客のデータあり",
        "ml_type": ""  # 「教師あり」「教師なし」「強化学習」のいずれかを入力
    },
    {
        "task": "全顧客を行動パターンで自動的にグループ分けする",
        "data_available": "行動ログのみ（グループの答えなし）",
        "ml_type": ""
    },
    {
        "task": "Google広告の入札単価を自動でリアルタイム最適化する",
        "data_available": "過去の入札結果と成果データ",
        "ml_type": ""
    },
    {
        "task": "メールの件名が良いか悪いかを自動判定する",
        "data_available": "過去の件名と開封率データあり",
        "ml_type": ""
    },
    {
        "task": "購買履歴から顧客の潜在的な興味関心クラスタを発見する",
        "data_available": "購買ログのみ（興味関心のラベルなし）",
        "ml_type": ""
    }
]

# 答え合わせ用
correct_answers = ["教師あり", "教師なし", "強化学習", "教師あり", "教師なし"]

score = 0
for i, task in enumerate(marketing_tasks):
    user_answer = task["ml_type"]
    correct = correct_answers[i]
    is_correct = user_answer == correct
    if is_correct:
        score += 1
    status = "正解" if is_correct else f"不正解（正解: {correct}）"
    print(f"問{i+1}: {task['task'][:25]}... → {user_answer or '未回答'} [{status}]")

print(f"\n得点: {score}/{len(marketing_tasks)}")

